tasks.description:
Add all UI control Zod schemas to `packages/shared/src/schemas.ts`. These schemas define the contract for agent UI commands, canvas content types, and UI state reporting.

## Implementation Steps

### 1. Add Canvas Content Schema

In `packages/shared/src/schemas.ts`, after the existing schema blocks (around line 60+), add:

```typescript
// === UI Control Schemas ===

export const UiCanvasContentSchema = z.discriminatedUnion('type', [
  z.object({
    type: z.literal('url'),
    url: z.string().url(),
    title: z.string().optional(),
    sandbox: z.string().optional(),
  }),
  z.object({
    type: z.literal('markdown'),
    content: z.string(),
    title: z.string().optional(),
  }),
  z.object({
    type: z.literal('json'),
    data: z.unknown(),
    title: z.string().optional(),
  }),
]);

export type UiCanvasContent = z.infer<typeof UiCanvasContentSchema>;
```

### 2. Add Panel, Sidebar Tab, and Toast Level Enums

```typescript
export const UiPanelIdSchema = z.enum(['settings', 'pulse', 'relay', 'mesh', 'picker']);
export type UiPanelId = z.infer<typeof UiPanelIdSchema>;

export const UiSidebarTabSchema = z.enum(['sessions', 'agents']);
export type UiSidebarTab = z.infer<typeof UiSidebarTabSchema>;

export const UiToastLevelSchema = z.enum(['success', 'error', 'info', 'warning']);
```

### 3. Add UiCommand Discriminated Union

```typescript
export const UiCommandSchema = z.discriminatedUnion('action', [
  // Panel commands
  z.object({ action: z.literal('open_panel'), panel: UiPanelIdSchema }),
  z.object({ action: z.literal('close_panel'), panel: UiPanelIdSchema }),
  z.object({ action: z.literal('toggle_panel'), panel: UiPanelIdSchema }),

  // Sidebar commands
  z.object({ action: z.literal('open_sidebar') }),
  z.object({ action: z.literal('close_sidebar') }),
  z.object({ action: z.literal('switch_sidebar_tab'), tab: UiSidebarTabSchema }),

  // Canvas commands
  z.object({
    action: z.literal('open_canvas'),
    content: UiCanvasContentSchema,
    preferredWidth: z.number().min(20).max(80).optional(),
  }),
  z.object({
    action: z.literal('update_canvas'),
    content: UiCanvasContentSchema,
  }),
  z.object({ action: z.literal('close_canvas') }),

  // Notification
  z.object({
    action: z.literal('show_toast'),
    message: z.string().max(500),
    level: UiToastLevelSchema.default('info'),
    description: z.string().max(1000).optional(),
  }),

  // Theme
  z.object({
    action: z.literal('set_theme'),
    theme: z.enum(['light', 'dark']),
  }),

  // Scroll
  z.object({
    action: z.literal('scroll_to_message'),
    messageId: z.string().optional(),
  }),

  // Agent switching
  z.object({
    action: z.literal('switch_agent'),
    cwd: z.string(),
  }),

  // Command palette
  z.object({ action: z.literal('open_command_palette') }),
]);

export type UiCommand = z.infer<typeof UiCommandSchema>;
```

### 4. Add UiCommand Event Schema

```typescript
export const UiCommandEventSchema = z.object({
  type: z.literal('ui_command'),
  command: UiCommandSchema,
});
```

### 5. Add `'ui_command'` to StreamEventTypeSchema

In the existing `StreamEventTypeSchema` enum array (around line 29-61), add `'ui_command'` to the array:

```typescript
export const StreamEventTypeSchema = z
  .enum([
    'text_delta',
    // ... existing entries ...
    'presence_update',
    'ui_command', // NEW
  ])
  .openapi('StreamEventType');
```

### 6. Add UiState Schema

```typescript
export const UiStateSchema = z.object({
  canvas: z.object({
    open: z.boolean(),
    contentType: z.enum(['url', 'markdown', 'json']).nullable(),
  }),
  panels: z.object({
    settings: z.boolean(),
    pulse: z.boolean(),
    relay: z.boolean(),
    mesh: z.boolean(),
  }),
  sidebar: z.object({
    open: z.boolean(),
    activeTab: UiSidebarTabSchema.nullable(),
  }),
  agent: z.object({
    id: z.string().nullable(),
    cwd: z.string().nullable(),
  }),
});

export type UiState = z.infer<typeof UiStateSchema>;
```

### 7. Export Types from `types.ts`

Add re-exports to `packages/shared/src/types.ts` for the new types: `UiCommand`, `UiCanvasContent`, `UiState`, `UiPanelId`, `UiSidebarTab`.

## Tests

Create `packages/shared/src/__tests__/ui-command-schemas.test.ts`:

```typescript
import { describe, it, expect } from 'vitest';
import {
  UiCommandSchema,
  UiCanvasContentSchema,
  UiStateSchema,
  UiPanelIdSchema,
  UiSidebarTabSchema,
  UiCommandEventSchema,
} from '../schemas';

describe('UiCommandSchema', () => {
  it('parses open_panel command', () => {
    const result = UiCommandSchema.parse({ action: 'open_panel', panel: 'pulse' });
    expect(result).toEqual({ action: 'open_panel', panel: 'pulse' });
  });

  it('parses close_panel command', () => {
    const result = UiCommandSchema.parse({ action: 'close_panel', panel: 'settings' });
    expect(result).toEqual({ action: 'close_panel', panel: 'settings' });
  });

  it('parses toggle_panel command', () => {
    const result = UiCommandSchema.parse({ action: 'toggle_panel', panel: 'relay' });
    expect(result).toEqual({ action: 'toggle_panel', panel: 'relay' });
  });

  it('parses open_sidebar command', () => {
    expect(UiCommandSchema.parse({ action: 'open_sidebar' })).toEqual({ action: 'open_sidebar' });
  });

  it('parses close_sidebar command', () => {
    expect(UiCommandSchema.parse({ action: 'close_sidebar' })).toEqual({ action: 'close_sidebar' });
  });

  it('parses switch_sidebar_tab command', () => {
    const result = UiCommandSchema.parse({ action: 'switch_sidebar_tab', tab: 'agents' });
    expect(result).toEqual({ action: 'switch_sidebar_tab', tab: 'agents' });
  });

  it('parses open_canvas with URL content', () => {
    const result = UiCommandSchema.parse({
      action: 'open_canvas',
      content: { type: 'url', url: 'https://example.com', title: 'Example' },
      preferredWidth: 60,
    });
    expect(result.action).toBe('open_canvas');
  });

  it('parses open_canvas with markdown content', () => {
    const result = UiCommandSchema.parse({
      action: 'open_canvas',
      content: { type: 'markdown', content: '# Hello' },
    });
    expect(result.action).toBe('open_canvas');
  });

  it('parses open_canvas with JSON content', () => {
    const result = UiCommandSchema.parse({
      action: 'open_canvas',
      content: { type: 'json', data: { key: 'value' } },
    });
    expect(result.action).toBe('open_canvas');
  });

  it('parses update_canvas command', () => {
    const result = UiCommandSchema.parse({
      action: 'update_canvas',
      content: { type: 'markdown', content: 'Updated' },
    });
    expect(result.action).toBe('update_canvas');
  });

  it('parses close_canvas command', () => {
    expect(UiCommandSchema.parse({ action: 'close_canvas' })).toEqual({ action: 'close_canvas' });
  });

  it('parses show_toast with defaults', () => {
    const result = UiCommandSchema.parse({ action: 'show_toast', message: 'Done!' });
    expect(result).toMatchObject({ action: 'show_toast', message: 'Done!', level: 'info' });
  });

  it('parses show_toast with all fields', () => {
    const result = UiCommandSchema.parse({
      action: 'show_toast',
      message: 'Error occurred',
      level: 'error',
      description: 'Details here',
    });
    expect(result).toMatchObject({ action: 'show_toast', level: 'error' });
  });

  it('parses set_theme command', () => {
    expect(UiCommandSchema.parse({ action: 'set_theme', theme: 'dark' })).toEqual({
      action: 'set_theme',
      theme: 'dark',
    });
  });

  it('parses scroll_to_message with optional messageId', () => {
    expect(UiCommandSchema.parse({ action: 'scroll_to_message' })).toEqual({
      action: 'scroll_to_message',
    });
    expect(UiCommandSchema.parse({ action: 'scroll_to_message', messageId: 'msg-123' })).toEqual({
      action: 'scroll_to_message',
      messageId: 'msg-123',
    });
  });

  it('parses switch_agent command', () => {
    expect(UiCommandSchema.parse({ action: 'switch_agent', cwd: '/home/user/project' })).toEqual({
      action: 'switch_agent',
      cwd: '/home/user/project',
    });
  });

  it('parses open_command_palette command', () => {
    expect(UiCommandSchema.parse({ action: 'open_command_palette' })).toEqual({
      action: 'open_command_palette',
    });
  });

  it('rejects invalid action', () => {
    expect(() => UiCommandSchema.parse({ action: 'invalid_action' })).toThrow();
  });

  it('rejects invalid panel id', () => {
    expect(() => UiCommandSchema.parse({ action: 'open_panel', panel: 'nonexistent' })).toThrow();
  });

  it('rejects preferredWidth outside range', () => {
    expect(() =>
      UiCommandSchema.parse({
        action: 'open_canvas',
        content: { type: 'markdown', content: 'hi' },
        preferredWidth: 5,
      })
    ).toThrow();
    expect(() =>
      UiCommandSchema.parse({
        action: 'open_canvas',
        content: { type: 'markdown', content: 'hi' },
        preferredWidth: 95,
      })
    ).toThrow();
  });

  it('rejects toast message over 500 chars', () => {
    expect(() =>
      UiCommandSchema.parse({ action: 'show_toast', message: 'x'.repeat(501) })
    ).toThrow();
  });
});

describe('UiCanvasContentSchema', () => {
  it('rejects invalid URL', () => {
    expect(() => UiCanvasContentSchema.parse({ type: 'url', url: 'not-a-url' })).toThrow();
  });

  it('accepts valid URL with optional sandbox override', () => {
    const result = UiCanvasContentSchema.parse({
      type: 'url',
      url: 'https://example.com',
      sandbox: 'allow-scripts',
    });
    expect(result).toMatchObject({ type: 'url', sandbox: 'allow-scripts' });
  });
});

describe('UiStateSchema', () => {
  it('parses a complete UI state', () => {
    const state = {
      canvas: { open: false, contentType: null },
      panels: { settings: false, pulse: false, relay: false, mesh: false },
      sidebar: { open: true, activeTab: 'sessions' },
      agent: { id: null, cwd: '/home/user/project' },
    };
    expect(UiStateSchema.parse(state)).toEqual(state);
  });

  it('rejects missing fields', () => {
    expect(() => UiStateSchema.parse({ canvas: { open: false } })).toThrow();
  });
});

describe('UiCommandEventSchema', () => {
  it('parses a ui_command event', () => {
    const event = {
      type: 'ui_command',
      command: { action: 'open_panel', panel: 'pulse' },
    };
    expect(UiCommandEventSchema.parse(event)).toEqual(event);
  });
});
```

## Acceptance Criteria

- All 14 UiCommand action variants parse correctly with valid input
- Invalid actions, invalid panel IDs, out-of-range preferredWidth, and overlong toast messages are rejected
- `'ui_command'` is present in `StreamEventTypeSchema` enum
- `UiStateSchema` validates the full state shape
- `UiCommandEventSchema` validates the event wrapper
- All new types are re-exported from `types.ts`
- `pnpm typecheck` passes across the monorepo
- All schema tests pass

Create the `executeUiCommand` plain function in `apps/client/src/layers/shared/lib/ui-action-dispatcher.ts`. This is a pure side-effect dispatcher with no React dependencies, callable from stream event handlers, command palette, and keyboard shortcuts.

## Implementation Steps

### 1. Create the Dispatcher File

Create `apps/client/src/layers/shared/lib/ui-action-dispatcher.ts`:

```typescript
import type { UiCommand, UiPanelId } from '@dorkos/shared/schemas';
import { toast } from 'sonner';

/** Dependencies injected by the caller. All are obtainable outside React. */
export interface DispatcherContext {
  /** useAppStore.getState() — the raw Zustand state object */
  store: {
    setSettingsOpen: (open: boolean) => void;
    setPulseOpen: (open: boolean) => void;
    setRelayOpen: (open: boolean) => void;
    setMeshOpen: (open: boolean) => void;
    setPickerOpen: (open: boolean) => void;
    settingsOpen: boolean;
    pulseOpen: boolean;
    relayOpen: boolean;
    meshOpen: boolean;
    pickerOpen: boolean;
    setSidebarOpen: (open: boolean) => void;
    setSidebarActiveTab: (tab: string) => void;
    setCanvasOpen: (open: boolean) => void;
    setCanvasContent: (content: unknown) => void;
    setCanvasPreferredWidth: (width: number | null) => void;
    setGlobalPaletteOpen: (open: boolean) => void;
  };
  /** Theme setter (from useTheme or stored ref) */
  setTheme: (theme: 'light' | 'dark') => void;
  /** Optional: scroll-to-message handler */
  scrollToMessage?: (messageId?: string) => void;
  /** Optional: agent switching handler */
  switchAgent?: (cwd: string) => void;
}

/**
 * Execute a UI command. Pure side-effect dispatcher — no return value,
 * no async, no React dependencies.
 */
export function executeUiCommand(ctx: DispatcherContext, command: UiCommand): void {
  const { store } = ctx;

  switch (command.action) {
    // --- Panels ---
    case 'open_panel':
      setPanelOpen(store, command.panel, true);
      break;
    case 'close_panel':
      setPanelOpen(store, command.panel, false);
      break;
    case 'toggle_panel':
      togglePanel(store, command.panel);
      break;

    // --- Sidebar ---
    case 'open_sidebar':
      store.setSidebarOpen(true);
      break;
    case 'close_sidebar':
      store.setSidebarOpen(false);
      break;
    case 'switch_sidebar_tab':
      store.setSidebarActiveTab(command.tab);
      store.setSidebarOpen(true);
      break;

    // --- Canvas ---
    case 'open_canvas':
      store.setCanvasOpen(true);
      store.setCanvasContent(command.content);
      if (command.preferredWidth != null) {
        store.setCanvasPreferredWidth(command.preferredWidth);
      }
      break;
    case 'update_canvas':
      store.setCanvasContent(command.content);
      break;
    case 'close_canvas':
      store.setCanvasOpen(false);
      break;

    // --- Toast ---
    case 'show_toast':
      toast[command.level](command.message, {
        description: command.description,
      });
      break;

    // --- Theme ---
    case 'set_theme':
      ctx.setTheme(command.theme);
      break;

    // --- Scroll ---
    case 'scroll_to_message':
      ctx.scrollToMessage?.(command.messageId);
      break;

    // --- Agent ---
    case 'switch_agent':
      ctx.switchAgent?.(command.cwd);
      break;

    // --- Command Palette ---
    case 'open_command_palette':
      store.setGlobalPaletteOpen(true);
      break;

    default: {
      // Exhaustive check — TypeScript will error if a variant is unhandled
      const _exhaustive: never = command;
      console.warn('[UiDispatcher] Unknown action:', (_exhaustive as UiCommand).action);
    }
  }
}

// --- Internal helpers ---

type PanelStore = Pick<
  DispatcherContext['store'],
  | 'setSettingsOpen'
  | 'setPulseOpen'
  | 'setRelayOpen'
  | 'setMeshOpen'
  | 'setPickerOpen'
  | 'settingsOpen'
  | 'pulseOpen'
  | 'relayOpen'
  | 'meshOpen'
  | 'pickerOpen'
>;

function setPanelOpen(store: PanelStore, panel: UiPanelId, open: boolean): void {
  const setterMap: Record<UiPanelId, (open: boolean) => void> = {
    settings: store.setSettingsOpen,
    pulse: store.setPulseOpen,
    relay: store.setRelayOpen,
    mesh: store.setMeshOpen,
    picker: store.setPickerOpen,
  };
  setterMap[panel]?.(open);
}

function togglePanel(store: PanelStore, panel: UiPanelId): void {
  const getterMap: Record<UiPanelId, boolean> = {
    settings: store.settingsOpen,
    pulse: store.pulseOpen,
    relay: store.relayOpen,
    mesh: store.meshOpen,
    picker: store.pickerOpen,
  };
  setPanelOpen(store, panel, !getterMap[panel]);
}
```

### 2. Update Shared Lib Barrel Export

In `apps/client/src/layers/shared/lib/index.ts`, add:

```typescript
export { executeUiCommand, type DispatcherContext } from './ui-action-dispatcher';
```

### 3. Verify the `store` Interface Compatibility

The `DispatcherContext.store` interface must match the subset of `AppState` used by the dispatcher. The existing `app-store.ts` already has all the panel setters (`setSettingsOpen`, `setPulseOpen`, `setRelayOpen`, `setMeshOpen`, `setPickerOpen`) and sidebar setters (`setSidebarOpen`, `setSidebarActiveTab`). The canvas setters (`setCanvasOpen`, `setCanvasContent`, `setCanvasPreferredWidth`) and `setGlobalPaletteOpen` are also present (canvas state is added in task 4.1). Use a Pick type or structural typing to keep the dependency minimal.

## Tests

Create `apps/client/src/layers/shared/lib/__tests__/ui-action-dispatcher.test.ts`:

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import { executeUiCommand, type DispatcherContext } from '../ui-action-dispatcher';
import type { UiCommand } from '@dorkos/shared/schemas';

// Mock sonner toast
vi.mock('sonner', () => ({
  toast: {
    success: vi.fn(),
    error: vi.fn(),
    info: vi.fn(),
    warning: vi.fn(),
  },
}));

import { toast } from 'sonner';

function createMockContext(): DispatcherContext {
  return {
    store: {
      setSettingsOpen: vi.fn(),
      setPulseOpen: vi.fn(),
      setRelayOpen: vi.fn(),
      setMeshOpen: vi.fn(),
      setPickerOpen: vi.fn(),
      settingsOpen: false,
      pulseOpen: false,
      relayOpen: false,
      meshOpen: false,
      pickerOpen: false,
      setSidebarOpen: vi.fn(),
      setSidebarActiveTab: vi.fn(),
      setCanvasOpen: vi.fn(),
      setCanvasContent: vi.fn(),
      setCanvasPreferredWidth: vi.fn(),
      setGlobalPaletteOpen: vi.fn(),
    },
    setTheme: vi.fn(),
    scrollToMessage: vi.fn(),
    switchAgent: vi.fn(),
  };
}

describe('executeUiCommand', () => {
  let ctx: DispatcherContext;

  beforeEach(() => {
    vi.clearAllMocks();
    ctx = createMockContext();
  });

  it('opens a panel', () => {
    executeUiCommand(ctx, { action: 'open_panel', panel: 'pulse' });
    expect(ctx.store.setPulseOpen).toHaveBeenCalledWith(true);
  });

  it('closes a panel', () => {
    executeUiCommand(ctx, { action: 'close_panel', panel: 'settings' });
    expect(ctx.store.setSettingsOpen).toHaveBeenCalledWith(false);
  });

  it('toggles a panel from closed to open', () => {
    executeUiCommand(ctx, { action: 'toggle_panel', panel: 'relay' });
    expect(ctx.store.setRelayOpen).toHaveBeenCalledWith(true);
  });

  it('toggles a panel from open to closed', () => {
    ctx.store.meshOpen = true;
    executeUiCommand(ctx, { action: 'toggle_panel', panel: 'mesh' });
    expect(ctx.store.setMeshOpen).toHaveBeenCalledWith(false);
  });

  it('opens sidebar', () => {
    executeUiCommand(ctx, { action: 'open_sidebar' });
    expect(ctx.store.setSidebarOpen).toHaveBeenCalledWith(true);
  });

  it('closes sidebar', () => {
    executeUiCommand(ctx, { action: 'close_sidebar' });
    expect(ctx.store.setSidebarOpen).toHaveBeenCalledWith(false);
  });

  it('switches sidebar tab and opens sidebar', () => {
    executeUiCommand(ctx, { action: 'switch_sidebar_tab', tab: 'agents' });
    expect(ctx.store.setSidebarActiveTab).toHaveBeenCalledWith('agents');
    expect(ctx.store.setSidebarOpen).toHaveBeenCalledWith(true);
  });

  it('opens canvas with content and preferred width', () => {
    executeUiCommand(ctx, {
      action: 'open_canvas',
      content: { type: 'markdown', content: '# Hello' },
      preferredWidth: 60,
    });
    expect(ctx.store.setCanvasOpen).toHaveBeenCalledWith(true);
    expect(ctx.store.setCanvasContent).toHaveBeenCalledWith({
      type: 'markdown',
      content: '# Hello',
    });
    expect(ctx.store.setCanvasPreferredWidth).toHaveBeenCalledWith(60);
  });

  it('opens canvas without preferred width', () => {
    executeUiCommand(ctx, {
      action: 'open_canvas',
      content: { type: 'url', url: 'https://example.com' },
    });
    expect(ctx.store.setCanvasPreferredWidth).not.toHaveBeenCalled();
  });

  it('updates canvas content', () => {
    executeUiCommand(ctx, {
      action: 'update_canvas',
      content: { type: 'json', data: { key: 'value' } },
    });
    expect(ctx.store.setCanvasContent).toHaveBeenCalledWith({
      type: 'json',
      data: { key: 'value' },
    });
  });

  it('closes canvas', () => {
    executeUiCommand(ctx, { action: 'close_canvas' });
    expect(ctx.store.setCanvasOpen).toHaveBeenCalledWith(false);
  });

  it('shows toast with default level', () => {
    executeUiCommand(ctx, { action: 'show_toast', message: 'Done!', level: 'info' });
    expect(toast.info).toHaveBeenCalledWith('Done!', { description: undefined });
  });

  it('shows toast with error level and description', () => {
    executeUiCommand(ctx, {
      action: 'show_toast',
      message: 'Failed',
      level: 'error',
      description: 'Something went wrong',
    });
    expect(toast.error).toHaveBeenCalledWith('Failed', {
      description: 'Something went wrong',
    });
  });

  it('sets theme', () => {
    executeUiCommand(ctx, { action: 'set_theme', theme: 'dark' });
    expect(ctx.setTheme).toHaveBeenCalledWith('dark');
  });

  it('scrolls to message', () => {
    executeUiCommand(ctx, { action: 'scroll_to_message', messageId: 'msg-123' });
    expect(ctx.scrollToMessage).toHaveBeenCalledWith('msg-123');
  });

  it('scrolls to bottom when messageId omitted', () => {
    executeUiCommand(ctx, { action: 'scroll_to_message' });
    expect(ctx.scrollToMessage).toHaveBeenCalledWith(undefined);
  });

  it('switches agent', () => {
    executeUiCommand(ctx, { action: 'switch_agent', cwd: '/home/user/project' });
    expect(ctx.switchAgent).toHaveBeenCalledWith('/home/user/project');
  });

  it('opens command palette', () => {
    executeUiCommand(ctx, { action: 'open_command_palette' });
    expect(ctx.store.setGlobalPaletteOpen).toHaveBeenCalledWith(true);
  });

  it('handles missing optional handlers gracefully', () => {
    const minCtx: DispatcherContext = {
      store: ctx.store,
      setTheme: vi.fn(),
    };
    // Should not throw when scrollToMessage and switchAgent are undefined
    expect(() => executeUiCommand(minCtx, { action: 'scroll_to_message' })).not.toThrow();
    expect(() =>
      executeUiCommand(minCtx, { action: 'switch_agent', cwd: '/path' })
    ).not.toThrow();
  });
});
```

## Acceptance Criteria

- `executeUiCommand` is a plain function (not a hook) in `layers/shared/lib/`
- It handles all 14 action types with an exhaustive switch
- TypeScript errors if a new UiCommand variant is added but not handled
- All 14+ test cases pass covering every action type
- Optional handlers (`scrollToMessage`, `switchAgent`) are called with `?.` and do not throw when undefined
- Exported from the shared lib barrel `index.ts`
- `pnpm typecheck` passes

Refactor `apps/client/src/layers/features/command-palette/model/use-palette-actions.ts` to delegate panel/feature actions to the shared `executeUiCommand` dispatcher. This must be a zero-behavior-change refactor — all existing command palette functionality continues working identically.

## Implementation Steps

### 1. Add Mapping Function

In `use-palette-actions.ts`, add a mapping function that converts palette action strings to UiCommand objects:

```typescript
import type { UiCommand } from '@dorkos/shared/schemas';
import { executeUiCommand, type DispatcherContext } from '@/layers/shared/lib';
import { useAppStore } from '@/layers/shared/model';

/**
 * Map a palette action string to a UiCommand.
 * Returns null for actions not yet representable as UiCommand (e.g., route navigation).
 */
function paletteActionToUiCommand(action: string, currentTheme: string): UiCommand | null {
  switch (action) {
    case 'openPulse':
      return { action: 'open_panel', panel: 'pulse' };
    case 'openRelay':
      return { action: 'open_panel', panel: 'relay' };
    case 'openMesh':
      return { action: 'open_panel', panel: 'mesh' };
    case 'openSettings':
      return { action: 'open_panel', panel: 'settings' };
    case 'browseFilesystem':
      return { action: 'open_panel', panel: 'picker' };
    case 'toggleTheme':
      return { action: 'set_theme', theme: currentTheme === 'dark' ? 'light' : 'dark' };
    case 'discoverAgents':
      return { action: 'open_panel', panel: 'mesh' };
    default:
      return null;
  }
}
```

### 2. Refactor handleFeatureAction

Replace the direct setter calls with dispatcher delegation:

**Before:**
```typescript
const handleFeatureAction = useCallback(
  (action: string) => {
    closePalette();
    switch (action) {
      case 'openPulse':
        setPulseOpen(true);
        break;
      case 'openRelay':
        setRelayOpen(true);
        break;
      case 'openMesh':
        setMeshOpen(true);
        break;
      case 'openSettings':
        setSettingsOpen(true);
        break;
      default:
        break;
    }
  },
  [closePalette, setPulseOpen, setRelayOpen, setMeshOpen, setSettingsOpen]
);
```

**After:**
