Create the server-side MCP tools that allow the agent to control the UI and query UI state. This follows the established `mcp-tools/` pattern with `tool()` from the Claude Agent SDK.

## Implementation Steps

### 1. Create ui-tools.ts

Create `apps/server/src/services/runtimes/claude-code/mcp-tools/ui-tools.ts`:

```typescript
import { tool } from '@anthropic-ai/claude-agent-sdk';
import { z } from 'zod';
import type { McpToolDeps } from './types.js';
import { jsonContent } from './types.js';

/** Get UI control tools. */
export function getUiTools(_deps: McpToolDeps) {
  return [
    tool({
      name: 'control_ui',
      description: `Control the DorkOS UI. Actions:
- open_panel / close_panel / toggle_panel: { panel: "settings"|"pulse"|"relay"|"mesh"|"picker" }
- open_sidebar / close_sidebar
- switch_sidebar_tab: { tab: "sessions"|"agents" }
- open_canvas: { content: { type: "url"|"markdown"|"json", ... }, preferredWidth?: 20-80 }
- update_canvas: { content: { type: "url"|"markdown"|"json", ... } }
- close_canvas
- show_toast: { message: string, level?: "success"|"error"|"info"|"warning", description?: string }
- set_theme: { theme: "light"|"dark" }
- scroll_to_message: { messageId?: string } (omit for bottom)
- switch_agent: { cwd: string }
- open_command_palette`,
      inputSchema: z.object({
        action: z.string().describe('The UI action to perform'),
      }).passthrough(),
      execute: async (input) => {
        // The full UiCommandSchema validation happens client-side when the
        // event is processed. Here we just forward the command as-is.
        // The session's eventQueue mechanism pushes this to the SSE stream.
        return jsonContent({ success: true, action: input.action });
      },
    }),
    tool({
      name: 'get_ui_state',
      description:
        'Get the current UI state — which panels are open, sidebar tab, canvas state, active agent. Use this after calling control_ui to verify the result, or when you need to make UI decisions mid-turn.',
      inputSchema: z.object({}),
      execute: async () => {
        // UI state is returned from the session's stored uiState.
        // The actual implementation reads from the session object,
        // which is populated by the client with each message.
        return jsonContent({
          note: 'UI state is injected by the runtime layer via session context.',
        });
      },
    }),
  ];
}

/**
 * Create the control_ui tool handler.
 * Returns a function that validates the command and emits a ui_command event.
 */
export function createControlUiHandler() {
  return async (args: Record<string, unknown>) => {
    return jsonContent({ success: true, action: args.action });
  };
}

/**
 * Create the get_ui_state tool handler.
 * Returns the UI state stored on the session.
 */
export function createGetUiStateHandler() {
  return async (args: Record<string, unknown>, sessionUiState?: unknown) => {
    const defaultState = {
      canvas: { open: false, contentType: null },
      panels: { settings: false, pulse: false, relay: false, mesh: false },
      sidebar: { open: true, activeTab: 'sessions' },
      agent: { id: null, cwd: null },
    };
    return jsonContent(sessionUiState ?? defaultState);
  };
}
```

Note: The actual integration with the SDK's event queue and session object depends on how `claude-code-runtime.ts` dispatches tool calls. The tool handlers here follow the same pattern as `pulse-tools.ts` and `relay-tools.ts`. The key mechanism is:
- `control_ui` validates the command and emits a `ui_command` event to the session's SSE stream
- `get_ui_state` reads the `uiState` property from the session (set by the client on each message)

The exact wiring into the SDK's tool execution depends on whether tools emit events via `session.eventQueue` (as described in the spec) or through the MCP server's response. Study the existing tool patterns in `claude-code-runtime.ts` and `message-sender.ts` to determine the correct injection point.

