### 5. Create CanvasJsonContent.tsx

A lightweight collapsible JSON tree viewer:

```typescript
import { useState, useCallback } from 'react';
import { cn } from '@/layers/shared/lib';
import { ChevronRight } from 'lucide-react';
import type { UiCanvasContent } from '@dorkos/shared/schemas';

interface CanvasJsonContentProps {
  content: Extract<UiCanvasContent, { type: 'json' }>;
}

/** Lightweight collapsible JSON tree viewer for canvas content. */
export function CanvasJsonContent({ content }: CanvasJsonContentProps) {
  return (
    <div className="p-4 font-mono text-sm">
      <JsonNode value={content.data} depth={0} />
    </div>
  );
}

interface JsonNodeProps {
  value: unknown;
  depth: number;
  keyName?: string;
}

function JsonNode({ value, depth, keyName }: JsonNodeProps) {
  const [collapsed, setCollapsed] = useState(depth > 2);
  const toggle = useCallback(() => setCollapsed((c) => !c), []);

  if (value === null) return <JsonLeaf keyName={keyName} value="null" className="text-muted-foreground" />;
  if (typeof value === 'boolean') return <JsonLeaf keyName={keyName} value={String(value)} className="text-blue-500" />;
  if (typeof value === 'number') return <JsonLeaf keyName={keyName} value={String(value)} className="text-green-500" />;
  if (typeof value === 'string') return <JsonLeaf keyName={keyName} value={`"${value}"`} className="text-amber-500" />;

  const isArray = Array.isArray(value);
  const entries = isArray
    ? (value as unknown[]).map((v, i) => [String(i), v] as const)
    : Object.entries(value as Record<string, unknown>);
  const bracket = isArray ? ['[', ']'] : ['{', '}'];

  return (
    <div style={{ paddingLeft: depth > 0 ? 16 : 0 }}>
      <button
        type="button"
        className="inline-flex items-center gap-0.5 hover:bg-muted rounded px-0.5 -ml-0.5"
        onClick={toggle}
      >
        <ChevronRight
          className={cn('size-3 transition-transform', !collapsed && 'rotate-90')}
        />
        {keyName != null && <span className="text-foreground">{keyName}: </span>}
        <span className="text-muted-foreground">
          {bracket[0]}
          {collapsed && `... ${entries.length} items`}
          {collapsed && bracket[1]}
        </span>
      </button>
      {!collapsed && (
        <>
          {entries.map(([k, v]) => (
            <JsonNode key={k} keyName={isArray ? undefined : k} value={v} depth={depth + 1} />
          ))}
          <div style={{ paddingLeft: 0 }} className="text-muted-foreground">
            {bracket[1]}
          </div>
        </>
      )}
    </div>
  );
}

function JsonLeaf({ keyName, value, className }: { keyName?: string; value: string; className: string }) {
  return (
    <div style={{ paddingLeft: 16 }}>
      {keyName != null && <span className="text-foreground">{keyName}: </span>}
      <span className={className}>{value}</span>
    </div>
  );
}
```

### 6. Create AgentCanvas.tsx

```typescript
import { Panel, PanelResizeHandle } from 'react-resizable-panels';
import { useAppStore } from '@/layers/shared/model';
import { CanvasUrlContent } from './CanvasUrlContent';
import { CanvasMarkdownContent } from './CanvasMarkdownContent';
import { CanvasJsonContent } from './CanvasJsonContent';
import { CanvasHeader } from './CanvasHeader';

/**
 * Resizable right-side canvas pane for agent-driven content.
 * Renders inside a PanelGroup alongside the ChatPanel.
 * Returns null when canvas is closed — no DOM footprint.
 */
export function AgentCanvas() {
  const canvasOpen = useAppStore((s) => s.canvasOpen);
  const canvasContent = useAppStore((s) => s.canvasContent);
  const setCanvasOpen = useAppStore((s) => s.setCanvasOpen);

  if (!canvasOpen || !canvasContent) return null;

  return (
    <>
      <PanelResizeHandle className="w-1.5 bg-border hover:bg-ring transition-colors" />
      <Panel
        id="agent-canvas"
        order={2}
        defaultSize={50}
        minSize={20}
        collapsible
        onCollapse={() => setCanvasOpen(false)}
      >
        <div className="flex h-full flex-col overflow-hidden rounded-lg border bg-card">
          <CanvasHeader
            title={canvasContent.title}
            contentType={canvasContent.type}
            onClose={() => setCanvasOpen(false)}
          />
          <div className="flex-1 overflow-auto">
            {canvasContent.type === 'url' && <CanvasUrlContent content={canvasContent} />}
            {canvasContent.type === 'markdown' && <CanvasMarkdownContent content={canvasContent} />}
            {canvasContent.type === 'json' && <CanvasJsonContent content={canvasContent} />}
          </div>
        </div>
      </Panel>
    </>
  );
}
```

